-- =========================================================
-- Seed data Shopee Dataset 2026
-- Sumber: rangkuman "Rincian Biaya Penjual Shopee per Kategori Produk"
-- (Pusat Edukasi Penjual Shopee, update per 25 Februari 2026), dikutip
-- dari artikel pihak ketiga yang menyebutkan sumber resminya.
-- Non-Star & Star/Star+ selalu sama persis (sesuai ketentuan Shopee).
-- Kolom mall_estimasi = 1 menandakan tarif Mall tidak disebutkan eksplisit
-- untuk item tsb di sumber, jadi dipakai tarif Mall terdekat di kelompok
-- yang sama sebagai pendekatan -- SEBAIKNYA DICEK ULANG berkala ke halaman
-- resmi Shopee (seller.shopee.co.id/edu/article/15965) karena tarif bisa berubah.
-- =========================================================

USE kalkulator_shopee;

ALTER TABLE shopee_dataset_2026
    ADD COLUMN IF NOT EXISTS mall_estimasi TINYINT(1) NOT NULL DEFAULT 0
    COMMENT '1 = tarif mall estimasi/pendekatan, bukan disebutkan eksplisit di sumber';

TRUNCATE TABLE shopee_dataset_2026;

